/* ===========================================================================
 * Decorative icons hidden from assistive tech (WCAG 1.3.1)
 *
 * startApp creates several Bootstrap Icons `<i>` glyphs inline — the in-input
 * search glyph (`bi bi-search search-icon`), the clear button's `bi-x-lg`, and
 * the dialog close button's `bi-x-lg`. Each is paired with a visible label or
 * an `aria-label` (the clear/close buttons), so the glyph itself is purely
 * decorative and MUST carry `aria-hidden="true"` so screen readers do not
 * announce the CSS `::before` generated content / private-use code point as
 * stray noise.
 * ========================================================================= */
describe('decorative icons hidden from assistive tech (WCAG 1.3.1)', () => {
  it('the in-input search icon (bi-search) carries aria-hidden="true"', () => {
    const { searchIcon } = setup();
    expect(searchIcon.getAttribute('aria-hidden')).toBe('true');
  });

  it('the clear button icon (bi-x-lg) carries aria-hidden="true"', () => {
    const { searchClearBtn } = setup();
    const clearIcon = searchClearBtn.querySelector('.bi') as HTMLElement;
    expect(clearIcon).toBeTruthy();
    expect(clearIcon.getAttribute('aria-hidden')).toBe('true');
  });

  it('the dialog close button icon (bi-x-lg) carries aria-hidden="true"', () => {
    const { closeBtn } = setup();
    const closeIcon = closeBtn.querySelector('.bi') as HTMLElement;
    expect(closeIcon).toBeTruthy();
    expect(closeIcon.getAttribute('aria-hidden')).toBe('true');
  });

  it('every <i> glyph startApp creates is hidden from AT (catch-all guard)', () => {
    // Defense-in-depth: every <i> element startApp emits is a decorative
    // Bootstrap Icons glyph and must carry aria-hidden="true". This catches a
    // regression that adds a new inline icon without hiding it, even one not
    // individually asserted above.
    const { root } = setup();
    const icons = Array.from(root.querySelectorAll('i'));
    expect(icons.length).toBeGreaterThan(0);
    for (const icon of icons) {
      expect(icon.getAttribute('aria-hidden'), icon.outerHTML).toBe('true');
    }
  });
});

