    expect(closeIcon.getAttribute('aria-hidden')).toBe('true');
  });

  it('every <i> glyph startApp creates is hidden from AT (catch-all guard)', () => {
    // Defense-in-depth: every <i> element startApp emits is a decorative
    // Bootstrap Icons glyph and must carry aria-hidden="true". This catches a
    // regression that adds a new inline icon without hiding it, even one not
    // individually asserted above.
    const { root } = setup();
    const icons = Array.from(root.querySelectorAll('i'));
    expect(icons.length).toBeGreaterThan(0);
    for (const icon of icons) {
      expect(icon.getAttribute('aria-hidden'), icon.outerHTML).toBe('true');
    }
